/* Additional gateway example: Express Gateway-style route with aggregation */
const express = require('express');
const fetch = require('node-fetch');
const app = express();

app.get('/api/dashboard', async (req, res) => {
  // gateway aggregates two backend calls
  const [userResp, statsResp] = await Promise.all([
    fetch('http://user-service/internal/profile', { headers: { Authorization: req.headers.authorization } }),
    fetch('http://stats-service/internal/summary', { headers: { Authorization: req.headers.authorization } })
  ]);
  const user = await userResp.json();
  const stats = await statsResp.json();
  res.json({ user, stats });
});

app.listen(3000);
